// Find all devices managed by Hall3 AAS
MATCH (h3:AssetAdministrationShell {idShort: 'Hall3'})-[:MANAGES_ASSET]->(asset:Asset)
RETURN h3.id, h3.idShort, asset.globalAssetId, asset.assetKind, asset.assetType

// Find all assets managed by Hall 3 AAS
MATCH (aas:AssetAdministrationShell {id: 'urn:aas:hall3'})-[:MANAGES_ASSET]->(a:Asset)
RETURN a.globalAssetId, a.assetKind, a.assetType, a.idShort AS assetIdShort

